<?php
namespace App\Http\Controllers\Dashboard;
use App\Http\Controllers\Controller;use App\Models\{LockDevice,LockProviderConfig,LockSyncAttempt,Room,RoomEvent,User};use App\Notifications\LockHealthAlert;use App\Services\Locks\{LockManager,ProviderManager};use App\Services\Security\AuditLogger;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Facades\Notification;use Illuminate\Support\Str;use Illuminate\Validation\Rule;use Inertia\{Inertia,Response};
class LockController extends Controller{
 public function index():Response{return Inertia::render('Dashboard/Locks/Locks',['devices'=>LockDevice::with('room')->latest('id')->get()->map(fn($d)=>['id'=>$d->id,'name'=>$d->name,'provider'=>$d->provider,'externalId'=>$d->external_id,'status'=>$d->status,'batteryLevel'=>$d->battery_level,'lastSeenAt'=>$d->last_seen_at?->toISOString(),'hardwareModel'=>$d->hardware_model,'firmwareVersion'=>$d->firmware_version,'capabilities'=>$d->capabilities??[],'syncStatus'=>$d->sync_status,'syncError'=>$d->sync_error,'lastSyncedAt'=>$d->last_synced_at?->toISOString(),'room'=>$d->room?['id'=>$d->room->id,'number'=>$d->room->number,'accessMarker'=>$d->room->access_marker]:null]),'rooms'=>Room::whereDoesntHave('lockDevice')->orderBy('number')->get(['id','number']),'providers'=>LockProviderConfig::orderBy('name')->get()->map(fn($p)=>['id'=>$p->id,'key'=>$p->key,'name'=>$p->name,'driver'=>$p->driver,'baseUrl'=>$p->base_url,'active'=>$p->active,'connectionStatus'=>$p->connection_status,'lastError'=>$p->last_error,'lastTestedAt'=>$p->last_tested_at?->toISOString(),'hasCredentials'=>filled($p->credentials),'webhookUrl'=>url("/webhooks/locks/{$p->key}")]),'discovered'=>session('discoveredLocks',[]),'recentAttempts'=>LockSyncAttempt::with('device:id,name')->latest()->limit(20)->get()->map(fn($a)=>['id'=>$a->id,'deviceName'=>$a->device?->name,'operation'=>$a->operation,'status'=>$a->status,'error'=>$a->error,'createdAt'=>$a->created_at?->toISOString()])]);}
 public function store(Request$request):RedirectResponse{$v=$request->validate(['name'=>['required','string','max:100'],'external_id'=>['required','string','max:255','unique:lock_devices,external_id'],'provider'=>['required','string','max:100'],'hardware_model'=>['nullable','string','max:100'],'firmware_version'=>['nullable','string','max:100']]);$this->validateProvider($v['provider']);$device=LockDevice::create([...$v,'status'=>'unknown','battery_level'=>100,'sync_status'=>'pending']);AuditLogger::record($request,'lock_registered','access','sensitive',"Lock {$device->name} registered in inventory.",$device);return back()->with('success','Lock added to inventory.');}
 public function saveProvider(Request$request):RedirectResponse{$v=$request->validate(['id'=>['nullable','exists:lock_provider_configs,id'],'name'=>['required','string','max:100'],'key'=>['required','alpha_dash','max:50',Rule::unique('lock_provider_configs','key')->ignore($request->input('id'))],'driver'=>['required',Rule::in(['simulator','generic_rest'])],'base_url'=>['nullable','url','max:500'],'token'=>['nullable','string','max:2000'],'webhook_secret'=>['nullable','string','min:16','max:255'],'active'=>['required','boolean']]);abort_if($v['driver']==='generic_rest'&&blank($v['base_url']),422,'A base URL is required for a REST provider.');$provider=isset($v['id'])?LockProviderConfig::findOrFail($v['id']):new LockProviderConfig;$provider->fill(['name'=>$v['name'],'key'=>$v['key'],'driver'=>$v['driver'],'base_url'=>$v['base_url'],'active'=>$v['active']]);if(filled($v['token']))$provider->credentials=['token'=>$v['token']];if(filled($v['webhook_secret']))$provider->webhook_secret=$v['webhook_secret'];elseif(!$provider->exists)$provider->webhook_secret=Str::random(48);$provider->save();AuditLogger::record($request,'lock_provider_saved','access','sensitive',"Lock provider {$provider->name} configured.",$provider);return back()->with('success','Provider configuration saved.');}
 public function testProvider(Request$request,LockProviderConfig$provider,ProviderManager$manager):RedirectResponse{try{$result=$manager->test($provider);$provider->update(['connection_status'=>'connected','last_error'=>null,'last_tested_at'=>now()]);AuditLogger::record($request,'lock_provider_tested','access','normal',"Connection to {$provider->name} succeeded.",$provider);return back()->with('success',$result['message']);}catch(\Throwable$e){$provider->update(['connection_status'=>'failed','last_error'=>$e->getMessage(),'last_tested_at'=>now()]);AuditLogger::record($request,'lock_provider_failed','access','warning',"Connection to {$provider->name} failed.",$provider,null,['error'=>$e->getMessage()]);return back()->withErrors(['provider'=>$e->getMessage()]);}}
 public function discover(Request$request,LockProviderConfig$provider,ProviderManager$manager):RedirectResponse{try{$devices=$manager->discover($provider);AuditLogger::record($request,'locks_discovered','access','normal',count($devices)." devices discovered from {$provider->name}.",$provider);return back()->with('discoveredLocks',array_map(fn($d)=>['provider'=>$provider->key,'external_id'=>(string)($d['external_id']??$d['id']??''),'name'=>$d['name']??$d['label']??'Discovered lock','hardware_model'=>$d['hardware_model']??$d['model']??null,'firmware_version'=>$d['firmware_version']??null,'battery_level'=>(int)($d['battery_level']??100),'status'=>$d['status']??'unknown','capabilities'=>$d['capabilities']??[]],$devices))->with('success',count($devices).' devices discovered.');}catch(\Throwable$e){return back()->withErrors(['provider'=>$e->getMessage()]);}}
 public function import(Request$request):RedirectResponse{$v=$request->validate(['devices'=>['required','array','min:1'],'devices.*.provider'=>['required','string'],'devices.*.external_id'=>['required','string','max:255'],'devices.*.name'=>['required','string','max:100'],'devices.*.hardware_model'=>['nullable','string','max:100'],'devices.*.firmware_version'=>['nullable','string','max:100'],'devices.*.battery_level'=>['nullable','integer','between:0,100'],'devices.*.status'=>['nullable','string','max:50'],'devices.*.capabilities'=>['nullable','array']]);$count=0;foreach($v['devices']as$data){$this->validateProvider($data['provider']);$device=LockDevice::updateOrCreate(['external_id'=>$data['external_id']],$data+['sync_status'=>'pending']);if($device->wasRecentlyCreated)$count++;}AuditLogger::record($request,'locks_imported','access','sensitive',"{$count} discovered locks imported.",null,null,['count'=>$count]);return back()->with('success',"{$count} locks imported.");}
 public function assign(Request$request,LockDevice$device):RedirectResponse{$v=$request->validate(['room_id'=>['required','integer','exists:rooms,id',Rule::unique('lock_devices','room_id')->ignore($device)]]);abort_if($device->room_id,422,'Unassign this lock before assigning it to another room.');$room=Room::findOrFail($v['room_id']);$device->update(['room_id'=>$room->id]);RoomEvent::create(['room_id'=>$room->id,'actor_id'=>$request->user()?->id,'event_type'=>'lock_paired','description'=>"Lock {$device->name} assigned to room {$room->number}.",'occurred_at'=>now()]);AuditLogger::record($request,'lock_assigned','access','sensitive',"Lock {$device->name} assigned to Room {$room->number}.",$device,null,['room_id'=>$room->id]);return back()->with('success','Lock assigned to room.');}
 public function unassign(Request$request,LockDevice$device):RedirectResponse{abort_unless($device->room_id,422,'Lock is not assigned.');$room=$device->room;abort_if($room?->checkins()->where('is_active',true)->exists(),422,'Cannot unassign a lock while the room has an active guest.');RoomEvent::create(['room_id'=>$room->id,'actor_id'=>$request->user()?->id,'event_type'=>'lock_unpaired','description'=>"Lock {$device->name} removed from room {$room->number}.",'occurred_at'=>now()]);AuditLogger::record($request,'lock_unassigned','access','sensitive',"Lock {$device->name} removed from Room {$room->number}.",$device,null,['room_id'=>$room->id]);$device->update(['room_id'=>null]);return back()->with('success','Lock returned to inventory.');}
 public function rotateMarker(Request$request,Room$room):RedirectResponse{$v=$request->validate(['reason'=>['required','string','min:10','max:500']]);$old=$room->access_marker;$room->update(['access_marker'=>(string)Str::uuid()]);RoomEvent::create(['room_id'=>$room->id,'actor_id'=>$request->user()->id,'event_type'=>'access_marker_rotated','description'=>'Room QR/NFC access marker regenerated. Reason: '.$v['reason'],'occurred_at'=>now()]);AuditLogger::record($request,'access_marker_rotated','access','critical',"Room {$room->number} QR/NFC marker regenerated.",$room,$v['reason'],['previous_marker_hash'=>hash('sha256',(string)$old)]);return back()->with('success','Room marker regenerated. Replace the printed QR code and rewrite the NFC tag.');}
 public function pair(Request$request,Room$room):RedirectResponse{abort_if($room->lockDevice,422,'This room already has a paired lock.');$device=LockDevice::create(['room_id'=>$room->id,'provider'=>'simulator','external_id'=>'sim-lock-'.Str::uuid(),'name'=>"Room {$room->number} Lock",'status'=>'online','battery_level'=>100,'last_seen_at'=>now(),'sync_status'=>'synced','last_synced_at'=>now(),'capabilities'=>['rfid','pin','mobile']]);RoomEvent::create(['room_id'=>$room->id,'actor_id'=>$request->user()?->id,'event_type'=>'lock_paired','description'=>'Simulated smart lock paired to room.','occurred_at'=>now()]);AuditLogger::record($request,'lock_paired','access','sensitive',"Simulated lock paired to Room {$room->number}.",$device,null,['room_id'=>$room->id]);return back()->with('success','Lock paired.');}
 public function unlock(Request$request,LockDevice$device,LockManager$manager):RedirectResponse{$v=$request->validate(['reason'=>['required','string','min:5','max:500']]);abort_unless($device->room_id,422,'Assign the lock to a room before unlocking.');$manager->unlock($device,$request->user(),$v['reason']);AuditLogger::record($request,'remote_unlock','access','critical',"Remote unlock executed for Room {$device->room?->number}.",$device,$v['reason'],['room_id'=>$device->room_id]);return back()->with('success','Remote unlock completed.');}
 public function emergency(Request$request,LockDevice$device):RedirectResponse{$v=$request->validate(['reason'=>['required','string','min:10','max:500']]);abort_unless($device->room_id,422,'Assign the lock first.');$device->commands()->create(['actor_id'=>$request->user()->id,'command'=>'manual_emergency_override','status'=>'pending_manual','response'=>['reason'=>$v['reason']]]);RoomEvent::create(['room_id'=>$device->room_id,'actor_id'=>$request->user()->id,'event_type'=>'emergency_access_requested','description'=>'Emergency manual access requested. Reason: '.$v['reason'],'occurred_at'=>now()]);AuditLogger::record($request,'emergency_access_requested','access','critical',"Emergency access requested for Room {$device->room?->number}.",$device,$v['reason']);return back()->with('success','Emergency manual-access procedure recorded. Use the hotel master-key protocol.');}
 public function sync(LockDevice$device,LockManager$manager):RedirectResponse{try{$manager->sync($device);$device->refresh();if($device->status!=='online'||$device->battery_level<25)Notification::send(User::whereIn('role',['super_admin','manager'])->where('status','active')->get(),new LockHealthAlert($device,"{$device->name} needs attention: {$device->status}, battery {$device->battery_level}%."));return back()->with('success','Lock status synchronized.');}catch(\Throwable$e){return back()->withErrors(['sync'=>$e->getMessage()]);}}
 public function retry(LockSyncAttempt$attempt,LockManager$manager):RedirectResponse{try{$manager->sync($attempt->device);$attempt->update(['status'=>'retried','completed_at'=>now()]);return back()->with('success','Synchronization retry completed.');}catch(\Throwable$e){return back()->withErrors(['sync'=>$e->getMessage()]);}}
 private function validateProvider(string$key):void{abort_unless($key==='simulator'||LockProviderConfig::where('key',$key)->where('active',true)->exists(),422,'Select an active lock provider.');}
}
